package com.anvritai.abhay.service;
import static com.anvritai.abhay.api.SearchDtos.*;import com.anvritai.abhay.repository.accounting.*;import com.anvritai.abhay.repository.banking.*;import com.anvritai.abhay.repository.document.*;import com.anvritai.abhay.repository.memory.*;import com.anvritai.abhay.repository.sales.*;import java.util.*;import org.springframework.data.domain.PageRequest;import org.springframework.stereotype.Service;import org.springframework.transaction.annotation.Transactional;
@Service public class GlobalSearchService{private final CompanyAccessService access;private final CustomerRepository customers;private final VendorRepository vendors;private final ItemRepository items;private final InvoiceRepository invoices;private final LedgerRepository ledgers;private final VoucherRepository vouchers;private final DocumentRepository documents;private final BankAccountRepository banks;private final MemoryEventRepository memory;
 public GlobalSearchService(CompanyAccessService access,CustomerRepository customers,VendorRepository vendors,ItemRepository items,InvoiceRepository invoices,LedgerRepository ledgers,VoucherRepository vouchers,DocumentRepository documents,BankAccountRepository banks,MemoryEventRepository memory){this.access=access;this.customers=customers;this.vendors=vendors;this.items=items;this.invoices=invoices;this.ledgers=ledgers;this.vouchers=vouchers;this.documents=documents;this.banks=banks;this.memory=memory;}
 @Transactional(readOnly=true) public SearchResponse search(UUID userId,UUID companyId,String raw,int requested){access.requireMembership(companyId,userId);String q=raw==null?"":raw.trim();if(q.length()<2)throw new AccountingRuleException("Search requires at least two characters.");if(q.length()>100)throw new AccountingRuleException("Search is limited to 100 characters.");int limit=Math.max(1,Math.min(requested,50));var page=PageRequest.of(0,Math.min(limit,10));List<SearchResult> out=new ArrayList<>();customers.findByCompanyIdAndDisplayNameContainingIgnoreCase(companyId,q,page).forEach(x->out.add(new SearchResult("CUSTOMER",x.getId(),x.getDisplayName(),x.getGstin(),x.getUpdatedAt())));vendors.findByCompanyIdAndDisplayNameContainingIgnoreCase(companyId,q,page).forEach(x->out.add(new SearchResult("VENDOR",x.getId(),x.getDisplayName(),x.getGstin(),x.getUpdatedAt())));items.findByCompanyIdAndNameContainingIgnoreCase(companyId,q,page).forEach(x->out.add(new SearchResult("ITEM",x.getId(),x.getName(),x.getSku(),x.getUpdatedAt())));invoices.findByCompanyIdAndInvoiceNumberContainingIgnoreCase(companyId,q,page).forEach(x->out.add(new SearchResult("INVOICE",x.getId(),x.getInvoiceNumber(),x.getStatus().name(),x.getUpdatedAt())));ledgers.findByCompanyIdAndNameContainingIgnoreCase(companyId,q,page).forEach(x->out.add(new SearchResult("LEDGER",x.getId(),x.getName(),x.getLedgerType().name(),x.getUpdatedAt())));vouchers.findByCompanyIdAndVoucherNumberContainingIgnoreCase(companyId,q,page).forEach(x->out.add(new SearchResult("VOUCHER",x.getId(),x.getVoucherNumber(),x.getStatus().name(),x.getUpdatedAt())));documents.findByCompanyIdAndOriginalFileNameContainingIgnoreCase(companyId,q,page).forEach(x->out.add(new SearchResult("DOCUMENT",x.getId(),x.getOriginalFileName(),x.getStatus().name(),x.getUpdatedAt())));banks.findByCompanyIdAndBankNameContainingIgnoreCase(companyId,q,page).forEach(x->out.add(new SearchResult("BANK_ACCOUNT",x.getId(),x.getBankName(),x.getAccountNumberMasked(),x.getUpdatedAt())));memory.findByCompanyIdAndSubjectKeyContainingIgnoreCase(companyId,q,page).forEach(x->out.add(new SearchResult("MEMORY",x.getId(),x.getSubjectKey(),x.getEventType(),x.getUpdatedAt())));List.of("Trial Balance","Profit and Loss","Balance Sheet","Cash Book","Bank Book","GST Summary").stream().filter(x->x.toLowerCase(Locale.ROOT).contains(q.toLowerCase(Locale.ROOT))).forEach(x->out.add(new SearchResult("REPORT",null,x,"Accounting report",null)));return new SearchResponse(q,limit,out.stream().sorted(Comparator.comparing(SearchResult::updatedAt,Comparator.nullsLast(Comparator.reverseOrder()))).limit(limit).toList());}
}
